('NV-B05', (SELECT id FROM buckets WHERE code='B'), '5-Year Crystal Award Name+Date', '5-year-crystal-award-name-date', 'Five years of brilliance, crystallised', 'Premium crystal award with 3D laser-engraved name and joining date. LED-lit base creates a luminous desk centrepiece that celebrates half a decade of commitment.', 'Teams marking a 5-year work anniversary', 'A lit award turns tenure into a daily, visible point of pride.', 8, NULL, NULL, NULL, NULL, NULL, 9, 5, 10, ARRAY['crystal','led'], ARRAY['laser_engrave']::personalization_type[], ARRAY['work_anniversary_5']::occasion_type[], ARRAY['achiever']::employee_archetype[], ARRAY['award','crystal','milestone','desk-test'], 'premium', false, false, true, 5),
('NV-B06', (SELECT id FROM buckets WHERE code='B'), '5-Year Leather Journal Numbered Edition', '5-year-leather-journal-numbered-edition', 'Five years of stories, bound in leather', 'Hand-numbered limited edition leather journal with the employee''s name debossed on cover. 200 pages of premium paper. A keepsake that honours five years of dedication.', 'Five-year milestones for makers and thinkers', 'A numbered edition makes the recipient feel rare, not routine.', 7, NULL, NULL, NULL, NULL, NULL, 7, 4, 25, ARRAY['leather','paper'], ARRAY['deboss']::personalization_type[], ARRAY['work_anniversary_5']::occasion_type[], ARRAY['creator','scholar']::employee_archetype[], ARRAY['journal','leather','keepsake','desk-test'], 'standard', false, false, true, 6),
('NV-B07', (SELECT id FROM buckets WHERE code='B'), '5-Year Desk Clock Wood+Brass', '5-year-desk-clock-wood-brass', 'Every second counts — especially after five years', 'Handcrafted wooden desk clock with brass accents and engraved nameplate. A daily reminder of time well spent, crafted from sheesham wood by Saharanpur artisans.', 'Five-year milestones for desk-bound leaders', 'A working clock earns desk space that a trophy never will.', 8, NULL, NULL, NULL, NULL, NULL, 9, 5, 10, ARRAY['wood','brass'], ARRAY['laser_engrave']::personalization_type[], ARRAY['work_anniversary_5']::occasion_type[], ARRAY['achiever','scholar']::employee_archetype[], ARRAY['clock','desk','milestone','desk-test'], 'premium', false, false, true, 7),
('NV-B08', (SELECT id FROM buckets WHERE code='B'), '7-Year Marble Nameplate Office', '7-year-marble-nameplate-office', 'Your name, carved in stone — because you''ve earned it', 'Makrana marble office nameplate with brass inlay lettering. Jaipur-crafted statement piece for the desk of someone who has built their legacy at the company.', 'Seven-year milestones for senior team members', 'A stone nameplate signals permanence, not just presence.', 9, NULL, NULL, NULL, NULL, NULL, 9, 5, 10, ARRAY['marble','brass'], ARRAY['laser_engrave']::personalization_type[], ARRAY['work_anniversary_7']::occasion_type[], ARRAY['achiever']::employee_archetype[], ARRAY['nameplate','marble','desk','desk-test'], 'premium', false, false, true, 8),
('NV-B09', (SELECT id FROM buckets WHERE code='B'), '10-Year Copper Bar Set 4pc', '10-year-copper-bar-set-4pc', 'A decade calls for a toast', 'Premium copper bar set — 4 Moscow mule mugs with name engraving, presented in a wooden tray. Moradabad-crafted celebration set for a milestone worth raising a glass to.', 'Decade milestones for social, well-loved teammates', 'A shared toast turns a personal milestone into a team moment.', 9, NULL, NULL, NULL, NULL, NULL, 9, 5, 10, ARRAY['copper','wood'], ARRAY['laser_engrave']::personalization_type[], ARRAY['work_anniversary_10']::occasion_type[], ARRAY['connector','achiever']::employee_archetype[], ARRAY['barware','copper','milestone','desk-test'], 'flagship', false, false, true, 9),
('NV-B10', (SELECT id FROM buckets WHERE code='B'), '10-Year Illustrated Career Map', '10-year-illustrated-career-map', 'Your journey, illustrated — from Day 1 to Year 10', 'Custom-commissioned illustrated timeline mapping the employee''s entire career journey at the company. Key projects, promotions, team changes, and milestones — hand-drawn and framed. The most emotional gift in our catalog.', 'Decade milestones that deserve a story', 'A hand-drawn journey says we remembered every chapter.', 10, NULL, NULL, NULL, NULL, NULL, 9, 5, 10, ARRAY['paper','frame'], ARRAY['print']::personalization_type[], ARRAY['work_anniversary_10']::occasion_type[], ARRAY['creator','achiever']::employee_archetype[], ARRAY['illustration','keepsake','milestone','desk-test'], 'premium', false, false, true, 10),
('NV-B11', (SELECT id FROM buckets WHERE code='B'), '15-Year Brass Trophy Heritage', '15-year-brass-trophy-heritage', 'Fifteen years. Weighty. Significant. Permanent.', 'Solid brass trophy on marble base with engraved nameplate. Heavy in the hand because the achievement is heavy in meaning. A boardroom-grade statement of loyalty.', 'Fifteen-year milestones for long-tenure leaders', 'Real weight in the hand makes recognition feel earned.', 9, NULL, NULL, NULL, NULL, NULL, 9, 5, 10, ARRAY['brass','marble'], ARRAY['laser_engrave']::personalization_type[], ARRAY['work_anniversary_15']::occasion_type[], ARRAY['achiever']::employee_archetype[], ARRAY['award','brass','milestone','desk-test'], 'flagship', false, false, true, 11),
('NV-B12', (SELECT id FROM buckets WHERE code='B'), '20-Year Achievement Coin Die-Cast', '20-year-achievement-coin-die-cast', 'Two decades of excellence — minted in metal', 'Custom die-cast commemorative coin in gold finish, presented in velvet-lined case. Collector-grade heirloom piece with name, years, and company crest. Limited edition feel.', 'Twenty-year milestones worth immortalising', 'A minted coin reads as legacy, not just longevity.', 8, NULL, NULL, NULL, NULL, NULL, 9, 5, 10, ARRAY['metal','velvet'], ARRAY['laser_engrave']::personalization_type[], ARRAY['work_anniversary_20']::occasion_type[], ARRAY['achiever']::employee_archetype[], ARRAY['coin','heirloom','milestone','desk-test'], 'flagship', false, false, true, 12),
('NV-B13', (SELECT id FROM buckets WHERE code='B'), 'Milestone Hoodie Year Design', 'milestone-hoodie-year-design', 'Wear your years with pride', 'Premium embroidered hoodie featuring the milestone year in bold design. 300 GSM fleece, name on sleeve, year on chest. The hoodie that says ''I built this place.''', 'Culture-led teams celebrating tenure', 'Wearable recognition has a longer shelf life than a trophy.', 7, NULL, NULL, NULL, NULL, NULL, 7, 4, 25, ARRAY['cotton-fleece'], ARRAY['embroidery']::personalization_type[], ARRAY['work_anniversary_3']::occasion_type[], ARRAY['connector','creator']::employee_archetype[], ARRAY['hoodie','wearable','milestone'], 'standard', false, false, true, 13),
('NV-B14', (SELECT id FROM buckets WHERE code='B'), 'Keepsake Box Sheesham Wood', 'keepsake-box-sheesham-wood', 'A box that holds more than objects — it holds memories', 'Hand-carved sheesham wood keepsake box with brass hinges and engraved lid. Designed to store all the small mementos from a career — badges, coins, cards, photos.', 'Milestone moments for sentimental keepers', 'A box for mementos makes every future memory feel worth saving.', 8, NULL, NULL, NULL, NULL, NULL, 7, 4, 25, ARRAY['wood','brass'], ARRAY['laser_engrave']::personalization_type[], ARRAY['work_anniversary_5']::occasion_type[], ARRAY['scholar','creator']::employee_archetype[], ARRAY['keepsake','wood','milestone','desk-test'], 'standard', false, false, true, 14),
('NV-B15', (SELECT id FROM buckets WHERE code='B'), 'LED Light Box Name+Year+Message', 'led-light-box-name-year-message', 'Your name in lights — because you deserve the spotlight', 'Custom LED light box displaying employee name, milestone year, and a personal message. Warm white glow creates a desk centrepiece that''s impossible to ignore.', 'Milestone recognition for the whole team to see', 'A glowing name on the desk is recognition nobody can miss.', 8, NULL, NULL, NULL, NULL, NULL, 7, 4, 25, ARRAY['led','acrylic'], ARRAY['print']::personalization_type[], ARRAY['work_anniversary_5']::occasion_type[], ARRAY['creator','connector']::employee_archetype[], ARRAY['led','desk','milestone','desk-test'], 'standard', false, false, true, 15)
