('NV-C12', (SELECT id FROM buckets WHERE code='C'), 'Brass Desk Globe Name Base', 'brass-desk-globe-name-base', 'For the leader who thinks globally', 'Vintage-style brass desk globe on wooden base with engraved nameplate. A timeless executive desk piece that signals ambition and worldview.', 'Spot awards for big-picture leaders', 'A desk globe signals ambition without saying a word.', 8, NULL, NULL, NULL, NULL, NULL, 9, 5, 10, ARRAY['brass','wood'], ARRAY['laser_engrave']::personalization_type[], ARRAY['spot_award']::occasion_type[], ARRAY['achiever','explorer']::employee_archetype[], ARRAY['globe','brass','desk','desk-test'], 'premium', false, false, true, 12)
