('NV-E09', (SELECT id FROM buckets WHERE code='E'), 'Premium Client Hamper 8-Item', 'premium-client-hamper-8-item', 'The flagship client gift — eight items of intention', 'Our most prestigious client gift. 8-item curated experience kit including copper decanter set, marble coasters, leather portfolio, artisanal tea, and more. Flagship packaging.', 'The most valued client relationships', 'A layered hamper makes the client feel like the priority.', 10, NULL, NULL, NULL, NULL, NULL, 9, 5, 5, ARRAY['copper','marble','leather','paper'], ARRAY['laser_engrave']::personalization_type[], ARRAY['client_appreciation']::occasion_type[], ARRAY['achiever']::employee_archetype[], ARRAY['hamper','flagship','client','desk-test'], 'flagship', false, false, true, 9),
('NV-E10', (SELECT id FROM buckets WHERE code='E'), 'Marble Visiting Card Holder', 'marble-visiting-card-holder', 'Cards held in marble — because first impressions are forever', 'Makrana marble visiting card holder with brass inlay and engraved client name. Jaipur-crafted desk piece that elevates the everyday act of exchanging cards.', 'Clients who value a refined desk', 'A desk piece used daily keeps your brand quietly present.', 7, NULL, NULL, NULL, NULL, NULL, 7, 4, 25, ARRAY['marble','brass'], ARRAY['laser_engrave']::personalization_type[], ARRAY['client_appreciation']::occasion_type[], ARRAY['achiever','scholar']::employee_archetype[], ARRAY['marble','desk','executive','desk-test'], 'standard', false, false, true, 10),
('NV-E11', (SELECT id FROM buckets WHERE code='E'), 'Brass Pen Stand Engraved', 'brass-pen-stand-engraved', 'A pen deserves a throne — so does its owner', 'Solid brass pen stand with engraved nameplate. Classic executive desk accessory that brings weight and warmth to the daily writing ritual.', 'Clients who appreciate classic craft', 'A weighty desk classic earns a permanent place by hand.', 7, NULL, NULL, NULL, NULL, NULL, 7, 4, 25, ARRAY['brass'], ARRAY['laser_engrave']::personalization_type[], ARRAY['client_appreciation']::occasion_type[], ARRAY['achiever','scholar']::employee_archetype[], ARRAY['brass','desk','executive','desk-test'], 'standard', false, false, true, 11),
('NV-E12', (SELECT id FROM buckets WHERE code='E'), 'Handcrafted Wood Box Pietra Dura', 'handcrafted-wood-box-pietra-dura', 'Heirloom-grade craftsmanship — a gift that outlives the deal', 'Handcrafted wooden box with pietra dura stone inlay work. Jaipur artisan tradition dating back to the Mughal era. A keepsake box that becomes a family heirloom.', 'Clients who appreciate heritage craft', 'An heirloom-grade gift outlives the deal that prompted it.', 9, NULL, NULL, NULL, NULL, NULL, 9, 5, 10, ARRAY['wood','marble'], ARRAY['laser_engrave']::personalization_type[], ARRAY['client_appreciation']::occasion_type[], ARRAY['achiever','creator']::employee_archetype[], ARRAY['heirloom','artisan','keepsake','desk-test'], 'flagship', false, false, true, 12)
