('NV-H05', (SELECT id FROM buckets WHERE code='H'), 'Organic Soy Candle Named Tin', 'organic-soy-candle-named-tin', '40 hours of warm glow — with your name on it', 'Hand-poured organic soy wax candle in a reusable tin with the recipient''s name printed on the lid. 40-hour burn time. Natural essential oil fragrance.', 'Eco-conscious teams who value calm', 'A reusable tin keeps the gift useful long after the wax is gone.', 6, NULL, NULL, NULL, NULL, NULL, 5, 3, 25, ARRAY['soy-wax','metal'], ARRAY['print']::personalization_type[], ARRAY['custom']::occasion_type[], ARRAY['root','creator']::employee_archetype[], ARRAY['eco','candle','desk','desk-test'], 'budget', false, false, true, 5),
('NV-H06', (SELECT id FROM buckets WHERE code='H'), 'Recycled Fabric Tote Named', 'recycled-fabric-tote-named', 'Carry your values — literally', 'Tote bag made from recycled fabric with printed name and eco-message. Daily-carry visibility for sustainable living. Reinforced handles for everyday use.', 'Sustainability-minded daily commuters', 'A recycled daily-carry bag turns values into a habit.', 5, NULL, NULL, NULL, NULL, NULL, 5, 3, 25, ARRAY['cotton'], ARRAY['print']::personalization_type[], ARRAY['custom']::occasion_type[], ARRAY['root','creator']::employee_archetype[], ARRAY['eco','tote','sustainable'], 'budget', false, false, true, 6),
('NV-H07', (SELECT id FROM buckets WHERE code='H'), 'Compostable Packaging Set', 'compostable-packaging-set', 'Zero waste gifting — from box to earth', 'Complete zero-waste packaging option using compostable materials. Mushroom packaging, seed paper cards, biodegradable ribbon. For companies where sustainability is non-negotiable.', 'Companies where sustainability is non-negotiable', 'Packaging that returns to earth makes the whole gift credible.', 5, NULL, NULL, NULL, NULL, NULL, 5, 3, 25, ARRAY['seed-paper','paper'], ARRAY['print']::personalization_type[], ARRAY['custom']::occasion_type[], ARRAY['root','scholar']::employee_archetype[], ARRAY['eco','packaging','zero-waste'], 'budget', false, false, true, 7),
('NV-H08', (SELECT id FROM buckets WHERE code='H'), 'Tree-Planting Certificate Framed', 'tree-planting-certificate-framed', 'A tree planted in your name — growing while you work', 'Framed certificate confirming a real tree planted in the recipient''s name. QR code links to tree location and growth updates. Partnered with verified reforestation organisations.', 'Teams who want their impact to be real', 'A real tree makes a gift that keeps growing without a desk.', 7, NULL, NULL, NULL, NULL, NULL, 7, 4, 25, ARRAY['paper','frame'], ARRAY['print']::personalization_type[], ARRAY['custom']::occasion_type[], ARRAY['root','achiever']::employee_archetype[], ARRAY['eco','certificate','desk','desk-test'], 'standard', false, false, true, 8),
('NV-H09', (SELECT id FROM buckets WHERE code='H'), 'Organic Cotton Tee Embroidered', 'organic-cotton-tee-embroidered', 'Soft on skin, gentle on the planet', 'GOTS-certified organic cotton t-shirt with embroidered name and company logo. Sustainable fashion that employees wear with pride and purpose.', 'Eco-conscious teams at onboarding', 'Certified fabric makes the sustainability claim believable.', 6, NULL, NULL, NULL, NULL, NULL, 5, 3, 25, ARRAY['organic-cotton'], ARRAY['embroidery']::personalization_type[], ARRAY['onboarding']::occasion_type[], ARRAY['root','connector']::employee_archetype[], ARRAY['eco','wearable','sustainable'], 'budget', false, false, true, 9),
('NV-H10', (SELECT id FROM buckets WHERE code='H'), 'Terracotta Planter Hand-Painted', 'terracotta-planter-hand-painted', 'Artisan earth — a living desk companion', 'Hand-painted terracotta planter by Bangalore artisans. Each piece unique. Comes with a starter plant and care card. Name tag attached with jute twine.', 'Teams who want a living desk piece', 'A living plant beats a plastic keepsake every single time.', 7, NULL, NULL, NULL, NULL, NULL, 7, 4, 25, ARRAY['terracotta','plant'], ARRAY['print']::personalization_type[], ARRAY['custom']::occasion_type[], ARRAY['creator','root']::employee_archetype[], ARRAY['eco','planter','desk','desk-test'], 'standard', false, false, true, 10),
('NV-H11', (SELECT id FROM buckets WHERE code='H'), 'Beeswax Wrap Set 3pc', 'beeswax-wrap-set-3pc', 'Wrap sustainably — at work and at home', 'Set of 3 beeswax food wraps in different sizes. Replaces plastic wrap. Printed with eco-tips and company branding. A daily-use reminder of sustainable values.', 'Teams cutting single-use plastic', 'A daily-use swap makes sustainability a habit, not a slogan.', 5, NULL, NULL, NULL, NULL, NULL, 5, 3, 25, ARRAY['beeswax','cotton'], ARRAY['print']::personalization_type[], ARRAY['custom']::occasion_type[], ARRAY['root','scholar']::employee_archetype[], ARRAY['eco','sustainable','zero-waste'], 'budget', false, false, true, 11),
('NV-H12', (SELECT id FROM buckets WHERE code='H'), 'Bamboo Cutlery Travel Set', 'bamboo-cutlery-travel-set', 'Your personal zero-waste kit — no more disposables', 'Bamboo fork, knife, spoon, chopsticks, and straw in a rolled cotton pouch. Engraved name on each piece. The everyday eco statement that replaces office disposables.', 'Teams ditching office disposables', 'A personal kit makes refusing disposables effortless.', 6, NULL, NULL, NULL, NULL, NULL, 5, 3, 25, ARRAY['bamboo','cotton'], ARRAY['laser_engrave']::personalization_type[], ARRAY['custom']::occasion_type[], ARRAY['root','scholar']::employee_archetype[], ARRAY['eco','travel','zero-waste'], 'budget', false, false, true, 12)
